// MARK: - Transaction Processor
class TransactionProcessor {
    static let shared = TransactionProcessor()
    private var accounts: [Account] = []
    private let encryptionKey: Data
    
    private init() {
        self.encryptionKey = EncryptionManager.shared.generateKey()
        loadAccounts()
    }
    
    func processTransaction(_ transaction: Transaction, from accountID: String) -> Result<Account, TransactionError> {
        guard let accountIndex = accounts.firstIndex(where: { $0.id == accountID }) else {
            return .failure(.accountNotFound)
        }
        
        var account = accounts[accountIndex]
        
        switch transaction.type {
        case .deposit:
            account.balance += transaction.amount
        case .withdrawal:
            if account.balance >= transaction.amount {
                account.balance -= transaction.amount
            } else {
                return .failure(.insufficientFunds)
            }
        case .transfer:
            guard let recipientAccount = accounts.first(where: { $0.accountNumber == transaction.recipient }) else {
                return .failure(.recipientNotFound)
            }
            if account.balance >= transaction.amount {
                account.balance -= transaction.amount
                recipientAccount.balance += transaction.amount
            } else {
                return .failure(.insufficientFunds)
            }
        case .payment:
            if account.balance >= transaction.amount {
                account.balance -= transaction.amount
            } else {
                return .failure(.insufficientFunds)
            }
        }
        
        account.transactions.append(transaction)
        accounts[accountIndex] = account
        
        saveAccounts()
        return .success(account)
    }
    
    func getAccountBalance(for accountID: String) -> Double? {
        return accounts.first { $0.id == accountID }?.balance
    }
    
    func getAllAccounts() -> [Account] {
        return accounts
    }
    
    private func loadAccounts() {
        if let data = SecureDataManager.shared.loadData(forKey: "accounts") {
            if let decryptedData = EncryptionManager.shared.decrypt(data, with: encryptionKey),
               let accounts = try? JSONDecoder().decode([Account].self, from: decryptedData) {
                self.accounts = accounts
            }
        }
    }
    
    private func saveAccounts() {
        if let encodedData = try? JSONEncoder().encode(accounts),
           let encryptedData = EncryptionManager.shared.encrypt(encodedData, with: encryptionKey) {
            SecureDataManager.shared.saveData(encryptedData, forKey: "accounts")
        }
    }
}

