// MARK: - Secure View Controller
class SecureBankingViewController: UIViewController {
    private var account: Account?
    private var transactionProcessor = TransactionProcessor.shared
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
        loadAccountData()
    }
    
    private func setupUI() {
        view.backgroundColor = .systemBackground
        title = "Secure Banking"
    }
    
    private func loadAccountData() {
        let accounts = transactionProcessor.getAllAccounts()
        if let firstAccount = accounts.first {
            account = firstAccount
            updateUI()
        }
    }
    
    private func updateUI() {
        guard let account = account else { return }
        
        let balanceLabel = UILabel()
        balanceLabel.text = String(format: "Balance: $%.2f", account.balance)
        balanceLabel.font = UIFont.boldSystemFont(ofSize: 24)
        balanceLabel.textAlignment = .center
        balanceLabel.translatesAutoresizingMaskIntoConstraints = false
        
        view.addSubview(balanceLabel)
        NSLayoutConstraint.activate([
            balanceLabel.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            balanceLabel.centerYAnchor.constraint(equalTo: view.centerYAnchor)
        ])
    }
    
    func performSecureTransaction(amount: Double, type: Transaction.TransactionType, description: String, recipient: String? = nil) {
        guard let accountID = account?.id else { return }
        
        let transaction = Transaction(
            id: UUID().uuidString,
            amount: amount,
            type: type,
            date: Date(),
            description: description,
            recipient: recipient
        )
        
        let result = transactionProcessor.processTransaction(transaction, from: accountID)
        
        switch result {
        case .success(let updatedAccount):
            account = updatedAccount
            updateUI()
        case .failure(let error):
            showError(error)
        }
    }
    
    private func showError(_ error: Error) {
        DispatchQueue.main.async {
            let alert = UIAlertController(title: "Transaction Error", message: error.localizedDescription, preferredStyle: .alert)
            alert.addAction(UIAlertAction(title: "OK", style: .default))
            self.present(alert, animated: true)
        }
    }
}

